function equilateralTriangle(ax, ay, bx, by) {
  const A = Point(ax, ay);
  const B = Point(bx, by);
  const side = Math.sqrt((bx - ax) ** 2 + (by - ay) ** 2);
  const cA = Circle(A, side);
  const cB = Circle(B, side);
  const pts = intersect(cA, cB);
  const C = pts[0];
  return [A, B, C];
}
